import React, { useState, useEffect } from 'react';
import './App.css';
import Topo from "./componentes/TopoOferta";
import Rodape from "./componentes/Rodape";
import { buscarOfertasPromocao } from "./componentes/ofertasService";

function App() {
  const [produtos, setProdutos] = useState([]);
  const [carrinho, setCarrinho] = useState([]);
  const [etapa, setEtapa] = useState('vitrine'); 
  const [modoCadastro, setModoCadastro] = useState(false);
  // Inicializa o usuário tentando ler do localStorage para não perder o login
  const [usuario, setUsuario] = useState(() => {
    const salvo = localStorage.getItem('usuario_logado');
    return salvo ? JSON.parse(salvo) : null;
  });
  const [formaPagamento, setFormaPagamento] = useState('');
  const [pedidoFinalizado, setPedidoFinalizado] = useState(null);
  const [historico, setHistorico] = useState([]);
  const [origemLogin, setOrigemLogin] = useState('checkout');
  const [formData, setFormData] = useState({ nome: '', email: '', senha: '', telefone: '', cep: '', endereco: '', cpf: '' });

  const fazerLogout = () => {
  localStorage.removeItem('usuario_logado');
  setUsuario(null);
  setEtapa('vitrine');
  window.location.reload(); 
};

useEffect(() => {
  const carregarDadosIniciais = async () => {
    try {
      const [resProd, resOfertas] = await Promise.all([
        fetch("http://localhost:3001/produtos"),
        fetch("http://localhost:3001/api/promocao_10")
      ]);

      const produtosNormais = await resProd.json();
      const ofertasView = await resOfertas.json();

      const produtosAtualizados = produtosNormais.map(p => {
        // Procura se esse produto está na VIEW de promoção
        const oferta = ofertasView.find(o => o.id === p.id);
        if (oferta) {
          return { 
            ...p, 
            Desconto_10porct: oferta.Desconto_10porct, 
            Valor_antigo: p.valor 
          };
        }
        return p;
      });

      setProdutos(produtosAtualizados);
    } catch (err) {
      console.error("Erro ao carregar dados:", err);
    }
  };
  carregarDadosIniciais();
}, []);
  // --- FUNÇÕES DO CARRINHO ---

  const adicionarAoCarrinho = (p) => {
    const itemExiste = carrinho.find(item => item.id === p.id);

    if (itemExiste) {
      // Se já existe, aumenta a quantidade
      setCarrinho(carrinho.map(item => 
        item.id === p.id ? { ...item, qtd: item.qtd + 1 } : item
      ));
    } else {
      // Se é novo, adiciona com qtd 1
      setCarrinho([...carrinho, { ...p, qtd: 1 }]);
    }
    // Removido o setEtapa('carrinho') para permitir continuar comprando
  };

  const alterarQuantidade = (id, delta) => {
    setCarrinho(carrinho.map(item => {
      if (item.id === id) {
        const novaQtd = item.qtd + delta;
        return novaQtd > 0 ? { ...item, qtd: novaQtd } : item;
      }
      return item;
    }).filter(item => item.qtd > 0)); // Opcional: remove se chegar a zero
  };

  const removerDoCarrinho = (id) => {
    setCarrinho(carrinho.filter(item => item.id !== id));
  };
  // CÁLCULO TOTAL CORRIGIDO: Usa Desconto_10porct se disponível
const totalProd = carrinho.reduce((acc, i) => {
  const precoEfetivo = i.Desconto_10porct ? parseFloat(i.Desconto_10porct) : parseFloat(i.valor);
  return acc + (precoEfetivo * (i.qtd || 1));
}, 0);
// Frete Grátis para PIX, senão 15.00
const valorFrete = formaPagamento === 'pix' ? 0 : 15.00;


// --- MÉTODOS DE AUTENTICAÇÃO E FINALIZAÇÃO ---
const handleAuth = async () => {
  const rota = modoCadastro ? 'cadastrar' : 'login';
  try {
    const response = await fetch(`http://localhost:3001/${rota}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(formData)
    });

    const dados = await response.json();

    if (response.ok) {
      setUsuario(dados); 
      localStorage.setItem('usuario_logado', JSON.stringify(dados)); // Salva para não deslogar 
      // O SEGREDO:
      if (origemLogin === 'historico') {
        const idParaBusca = dados.id_cliente || dados.id;
        // Se ele for pelo botão de histórico, busca os dados da VIEW
        const resH = await fetch(`http://localhost:3001/historico/${idParaBusca}`);
        const dadosH = await resH.json();
        setHistorico(Array.isArray(dadosH) ? dadosH : []);
        setEtapa('historico');
      } else {
        setEtapa('checkout');
      }
    } else {
      alert(dados.message || "Erro na autenticação");
    }
  } catch (err) {
    alert("Erro de conexão.");
  }
};
     
const finalizar = async () => {
  // 1. Verificação de segurança
  const userAtual = usuario || JSON.parse(localStorage.getItem('usuario_logado'));
  if (!userAtual || !userAtual.id) {
    setEtapa('login');
    return alert("Usuário não identificado. Por favor, faça login novamente.");
  }

  const novoNumeroPedido = Math.floor(Math.random() * 100000);

  try {
    // Percorremos cada item do carrinho
    for (const item of carrinho) {
      const valorVenda = item.Desconto_10porct ? item.Desconto_10porct : item.valor;
      alert(`Enviando Produto: ${item.produto} | ID: ${item.id}`);
      // DECLARAÇÃO DA VARIÁVEL: Ela deve estar AQUI DENTRO
      
  const corpoVenda = {
  id_pedido: novoNumeroPedido,
  id_cliente: usuario.id,
  produto: item.produto,
  quantidade: item.qtd || 1,
  valor: valorVenda,
  id_produto: item.id // <--- TEM QUE TER ESSE NOME PARA O SERVER.JS LER
};
     const response = await fetch("http://localhost:3001/venda_cliente", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(corpoVenda)
        });
        if (!response.ok) throw new Error("Erro ao gravar item");
      }
      setPedidoFinalizado({ numero: novoNumeroPedido });
      setEtapa('sucesso');
      setCarrinho([]);
    } catch (err) {
      alert("❌ Falha no Pedido: " + err.message);
    }
  };

  const carregarHistorico = async (userParam) => {
    const userAtivo = userParam || usuario;
    if (!userAtivo) {
      setOrigemLogin('historico');
      setEtapa('login');
      return;
    }
    const idParaBusca = userAtivo.id_cliente || userAtivo.id;
    try {
      const response = await fetch(`http://localhost:3001/historico/${idParaBusca}`);
      const dados = await response.json();
      setHistorico(Array.isArray(dados) ? dados : []);
      setEtapa('historico');
    } catch (err) {
      alert("Erro ao buscar histórico.");
    }
  };

const carregarOfertas = async () => {
    const ofertas = await buscarOfertasPromocao();
    if (ofertas.length > 0) {
      setProdutos(ofertas); // Atualiza a vitrine com a VIEW do banco
      setEtapa('vitrine');  // Garante que o usuário veja os produtos
    } else {
      alert("Nenhuma oferta encontrada na Mercearia.");
    }
  };
  
  
  return (
    <div className="App">
<Topo 
      totalItens={carrinho.length} 
      abrirCarrinho={() => setEtapa('carrinho')} 
      verHistorico={carregarHistorico} 
      usuarioLogado={usuario} 
      setProdutos={setProdutos}
      onLogout={fazerLogout}
    /> 
      <main className="conteudo-principal">
     {etapa === 'vitrine' && (
  <div className="container-vitrine">
    
    {/* BOTÃO VOLTAR: Só aparece quando estamos vendo as ofertas */}
    {produtos.some(p => p.Desconto_10porct) && (
  <div className="barra-topo-ofertas">
    <button className="btn-voltar-inicial" onClick={() => window.location.reload()}>
      🏠 Voltar
    </button>
    <h2 className="titulo-ofertas">🔥 Ofertas de Mercearia</h2>
  </div>
)}

    <div className="grid-produtos">
      {produtos.map((p) => (
        <div key={p.id} className="card">
          {p.Desconto_10porct && (
            <div className="badge-promo">10% OFF</div>
          )}
          
          <img src={p.imagem_url || p.foto} alt={p.produto} />
          <h3>{p.produto}</h3>

          <div className="preco-container">
            {p.Desconto_10porct ? (
              <>
                <div className="preco-linha">
                  <span className="texto-label">De:</span>
                  <span className="preco-antigo">R$ {parseFloat(p.Valor_antigo).toFixed(2)}</span>
                </div>
                <div className="preco-linha">
                  <span className="texto-label">Por:</span>
                  <span className="preco-novo">R$ {parseFloat(p.Desconto_10porct).toFixed(2)}</span>
                </div>
              </>
            ) : (
              <span className="preco-normal">R$ {parseFloat(p.valor).toFixed(2)}</span>
            )}
          </div>

          <button className="btn-comprar" onClick={() => adicionarAoCarrinho(p)}>
            Comprar
          </button>
        </div>
      ))}
    </div>
  </div>
)}
        

        {etapa === 'carrinho' && (
          
          <div className="container-venda">
            <h2>🛒 Carrinho</h2>
{carrinho.length === 0 ? (
      /* --- Se o carrinho estiver VAZIO, mostra isso --- */
      <>
        <p>O carrinho está vazio.</p>
        <button className="btn-voltar-inicial" onClick={() => setEtapa('vitrine')}>
          🏠 Voltar para o Início
        </button>
      </>
    ) : (
      /* --- Se o carrinho TIVER ITENS, mostra isso --- */
      <>
                {carrinho.map((i) => (
                  <div key={i.id} className="item-carrinho-detalhado">
                    <img src={i.imagem_url} alt={i.produto} className="img-mini" />
                    <div className="info-item">
                      <span className="nome-p">{i.produto}</span>
                      <span className="preco-p">R$ {parseFloat(i.valor).toFixed(2)}</span>
                    </div>
                    <div className="controles-qtd">
                      <button onClick={() => alterarQuantidade(i.id, -1)}>-</button>
                      <span className="qtd-num">{i.qtd}</span>
                      <button onClick={() => alterarQuantidade(i.id, 1)}>+</button>
                    </div>
                    <button className="btn-remover" onClick={() => removerDoCarrinho(i.id)}>🗑️</button>
   
                  </div>
                ))}
                <div className="resumo-carrinho">
                  <h3>Total: R$ {totalProd.toFixed(2)}</h3>
                  <div className="botoes-fluxo">
                    <button className="btn-secundario" onClick={() => setEtapa('vitrine')}>Continuar Comprando</button>
                    <button className="btn-p" onClick={() => setEtapa('login')}>Finalizar Pedido</button>
                  </div>
                </div>
          </>
            )}
          </div>
        )}           
{etapa === 'login' && (
  <div className="container-venda">
    <button className="btn-voltar-inicial" onClick={() => window.location.reload()}>
      🏠 Voltar
    </button>
    <h2>{modoCadastro ? "📝 Cadastro" : "🔐 Login"}</h2>
    
    {/* Campos comuns tanto para Login quanto para Cadastro */}
    <input 
      className="in-v" 
      placeholder="E-mail" 
      onChange={e => setFormData({...formData, email: e.target.value})} 
    />
    <input 
      className="in-v" 
      type="password" 
      placeholder="Senha" 
      onChange={e => setFormData({...formData, senha: e.target.value})} 
    />

    {/* Campos EXCLUSIVOS do Cadastro */}
    {modoCadastro && (
      <>
        <input 
          className="in-v" 
          placeholder="Nome Completo" 
          onChange={e => setFormData({...formData, nome: e.target.value})} 
        />
        <input 
          className="in-v" 
          type="text" 
          placeholder="Telefone (DDD + Número)" 
          onChange={e => setFormData({...formData, telefone: e.target.value})} 
        />
        <input 
          className="in-v" 
          placeholder="CEP" 
          onChange={e => setFormData({...formData, cep: e.target.value})} 
        />
        <input 
          className="in-v" 
          placeholder="Endereço Completo" 
          onChange={e => setFormData({...formData, endereco: e.target.value})} 
        />
        <input 
          className="in-v" 
          placeholder="CPF (apenas números)" 
          onChange={e => setFormData({...formData, cpf: e.target.value})} 
        />
      </>
    )}

    <button className="btn-p" onClick={handleAuth}>
      {modoCadastro ? "Finalizar Cadastro" : "Entrar"}
    </button>
    
    <p className="link-troca" onClick={() => setModoCadastro(!modoCadastro)}>
      {modoCadastro ? "Já tem conta? Faça Login" : "Não tem conta? Cadastre-se"}
    </p>
  </div>
)}

        {etapa === 'checkout' && (
          <div className="container-venda">
            <h2>📍 Entrega para {usuario?.nome}</h2>
            
            {/* Resumo detalhado dos valores */}
            <select className="in-v" onChange={e => setFormaPagamento(e.target.value)}>
              
              <option value="">Pagamento...</option>
              <option value="pix">Pix</option>
              <option value="cartao">Cartão</option>
            </select>
            <h3>Produtos: R$ {totalProd.toFixed(2)}</h3>
                <p>
        Frete: {formaPagamento === 'pix' ? (
          <strong style={{ color: '#28a745' }}>GRÁTIS (PIX)</strong>
        ) : (
          `R$ ${valorFrete.toFixed(2)}`
        )}
      </p>
        
            <button className="btn-p" onClick={finalizar}>Confirmar Pedido</button>
             <button className="btn-voltar-inicial" onClick={() => window.location.reload()}>
      🏠 Voltar
    </button>
          </div>
        )}

        {etapa === 'sucesso' && (
          <div className="alerta-s">
            <h2>✅ Pedido #{pedidoFinalizado?.numero} Confirmado!</h2>
            <button className="btn-p" onClick={() => setEtapa('vitrine')}>Voltar</button>
          </div>
        )}
        {etapa === 'historico' && (
  <div className="container-venda">
   
    <h2>📋 Meu Histórico de Pedidos</h2>
    {historico.length === 0 ? <p>Você ainda não realizou pedidos.</p> : (
      <table className="tabela-historico">
        <thead>
          <tr>
            <th>Pedido</th>
            <th>Produto</th>
            <th>Data da Venda</th>
            <th>Qtd</th>
            <th>Valor</th>
          </tr>
        </thead>
        <tbody>
        {Array.isArray(historico) && historico.map((ped, index) => (
  <tr key={index}>
    <td>#{ped.numero_pedido}</td> 
    <td>{ped.itens_do_pedido}</td>
    <td>{ped.data_venda}</td> {/* Adicionei a data, já que sua VIEW tem */}
    <td>{ped.quantidades}</td>
    <td>R$ {parseFloat(ped.valor_total_pedido).toFixed(2)}</td>
  </tr>
))}
        </tbody>
      </table>
    )}
    <button className="btn-p" onClick={() => setEtapa('vitrine')}>Voltar para Loja</button>
  </div>
)}
      </main>
      <Rodape />
    </div>
  );
}

export default App;
